import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"穿月","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/3.B级/穿月.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/3.B级/穿月.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/远程武器/3.B级/穿月.md"};function l(i,a,_,b,p,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"穿月",tabindex:"-1"},[s("穿月 "),e("a",{class:"header-anchor",href:"#穿月","aria-label":'Permalink to "穿月"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌038")])])],-1),o('<h1 id="穿月-1" tabindex="-1">穿月 <a class="header-anchor" href="#穿月-1" aria-label="Permalink to &quot;穿月&quot;">​</a></h1><p>穿月<br> B+2500<br> 魔幻本质<br> 描述：这是一把金色的金属长弓，没有弓弦，有一只金色的把手，弓身正中是向前反弓的两枚尖牙般的金属月弧，有红色的魔兽晶核整齐地镶嵌在弓身上，在夜晚会散发出美轮美奂的白光。握着这把由月岭魔金铸成的弦月型金色长弓，仿佛能感觉到月光在自己的体内流淌，无弦的弓在手中等待着，将手搭在那不存在的弦上，魔力会相互吸引，在手中幻化出银白的魔力弓弦与能量箭矢，松手，寂静无声，月光，照耀在敌人穿孔的身躯之后，消散。<br> 分类：长弓<br> 武器伤害：22L<br> 基础效果：【双手】【高速3】【破甲1】<br> 武器体积：3<br> 伤害类型：物理-穿刺<br> 特性：【魔弓穿月】<br> 【魔弓穿月】：该武器在进行攻击时可以消耗一个花招动作进行一次瞄准；该武器可以正常搭箭射击，武器中的魔力会自动形成弓弦，在射击时，可以支付至多6点魔力，以此换取攻击上的额外【支付魔力】*2L武器伤害提升。<br> 仅在具有月亮存在的夜晚场景时，该武器具有以下额外能力：<br> 无需搭箭，可以直接凝聚月光进行射击，视为具有【无限子弹】，能量汇具而成的子弹具有【法破】特性，并且在月光的加持下，你的敏感范围提升一倍，攻击加骰提升一级（至多为8加骰），在进行攻击时，若自身魔力池不为空，且这次攻击至少消耗了1点魔力，这次攻击额外具有4点附加成功。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
